// // This comment suggests that the latch will store the input data only when the enable signal is inactive.
module top_module(EN, ARST, D, Q);parameter WIDTH = 0; 
 parameter EN_POLARITY = 1'b1; 
 parameter ARST_POLARITY = 1'b1; 
 parameter ARST_VALUE = 0; 
 input EN, ARST; 
 input [WIDTH-1:0] D; 
 output reg [WIDTH-1:0] Q; 
 always @* begin 
  if (ARST == ARST_POLARITY) 
  Q = ARST_VALUE; 
  else if (EN == EN_POLARITY) 
  Q = D; 
 end 
 endmodule
